class ChromaticNumber {
    static func solve(_ arr: [Int]) -> Int {
        if arr.count < 2 { return 0 }
        let n = arr[0]
        let m = arr[1]

        if arr.count < 2 + 2 * m { return 0 }
        if n == 0 { return 0 }

        var adj = [[Bool]](repeating: [Bool](repeating: false, count: n), count: n)
        for i in 0..<m {
            let u = arr[2 + 2 * i]
            let v = arr[2 + 2 * i + 1]
            if u >= 0 && u < n && v >= 0 && v < n {
                adj[u][v] = true
                adj[v][u] = true
            }
        }

        var color = [Int](repeating: 0, count: n)

        func isSafe(_ u: Int, _ c: Int) -> Bool {
            for v in 0..<n {
                if adj[u][v] && color[v] == c {
                    return false
                }
            }
            return true
        }

        func graphColoringUtil(_ u: Int, _ k: Int) -> Bool {
            if u == n { return true }

            for c in 1...k {
                if isSafe(u, c) {
                    color[u] = c
                    if graphColoringUtil(u + 1, k) {
                        return true
                    }
                    color[u] = 0
                }
            }
            return false
        }

        for k in 1...n {
            if graphColoringUtil(0, k) {
                return k
            }
        }

        return n
    }
}

export function chromaticNumber(arr: number[]): number {
  if (arr.length < 2) return 0;
  const n = arr[0];
  const m = arr[1];

  if (arr.length < 2 + 2 * m) return 0;
  if (n === 0) return 0;

  const adj: boolean[][] = Array.from({ length: n }, () => Array(n).fill(false));
  for (let i = 0; i < m; i++) {
    const u = arr[2 + 2 * i];
    const v = arr[2 + 2 * i + 1];
    if (u >= 0 && u < n && v >= 0 && v < n) {
      adj[u][v] = true;
      adj[v][u] = true;
    }
  }

  const color: number[] = new Array(n).fill(0);

  function isSafe(u: number, c: number): boolean {
    for (let v = 0; v < n; v++) {
      if (adj[u][v] && color[v] === c) {
        return false;
      }
    }
    return true;
  }

  function graphColoringUtil(u: number, k: number): boolean {
    if (u === n) return true;

    for (let c = 1; c <= k; c++) {
      if (isSafe(u, c)) {
        color[u] = c;
        if (graphColoringUtil(u + 1, k)) {
          return true;
        }
        color[u] = 0;
      }
    }
    return false;
  }

  for (let k = 1; k <= n; k++) {
    if (graphColoringUtil(0, k)) {
      return k;
    }
  }

  return n;
}

export function chromaticNumber(arr: number[]): number {
    const n = arr[0], m = arr[1];
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) {
        const u = arr[2+2*i], v = arr[2+2*i+1];
        adj[u].push(v); adj[v].push(u);
    }
    if (m === 0) return 1;
    const color = new Array(n).fill(0);

    function canColor(v: number, c: number): boolean {
        for (const u of adj[v]) if (color[u] === c) return false;
        return true;
    }

    function backtrack(v: number, k: number): boolean {
        if (v === n) return true;
        for (let c = 1; c <= k; c++) {
            if (canColor(v, c)) {
                color[v] = c;
                if (backtrack(v + 1, k)) return true;
                color[v] = 0;
            }
        }
        return false;
    }

    for (let k = 1; k <= n; k++) {
        color.fill(0);
        if (backtrack(0, k)) return k;
    }
    return n;
}
